const root = ($env.NEFALIX_REPO_ROOT || '/opt/nefalix').replace(/\/$/, '');
const body = $json.body ?? $json;
const parts = ['cd', JSON.stringify(root), '&&', 'python3', 'execution/social-generate-next.py'];
if (body.slug) parts.push('--slug', JSON.stringify(String(body.slug)));
if (body.post_number) parts.push('--post-number', String(Number(body.post_number)));
if (body.platform) parts.push('--platform', JSON.stringify(String(body.platform)));
if (body.skip_render) parts.push('--skip-render');
if (body.skip_wa) parts.push('--skip-wa');
if (body.dry_run) parts.push('--dry-run');
return [{ json: { command: parts.join(' ') } }];

let parsed = {};
try {
  parsed = JSON.parse($json.stdout || '{}');
} catch (e) {
  parsed = { raw: $json.stdout, stderr: $json.stderr };
}
return [{ json: { ok: true, step: 'generate', ...parsed } }];

let parsed = {};
try {
  parsed = JSON.parse($json.stdout || '{}');
} catch (e) {
  parsed = { raw: $json.stdout, stderr: $json.stderr };
}
return [{ json: { ok: true, step: 'publish', ...parsed } }];

const body = $json.body ?? $json;
const token = String(body.token || body.approval_token || '').trim();
const action = String(body.action || 'approve').toLowerCase();
const scheduledAt = body.scheduled_at || body.scheduledAt || null;
const approvedBy = body.approved_by || body.approvedBy || 'whatsapp';
if (!token) throw new Error('token gerekli');

const sbBase = ($env.SUPABASE_URL || 'http://host.docker.internal:54321').replace(/\/$/, '');
const sbKey = $env.SUPABASE_SERVICE_ROLE_KEY;
if (!sbKey) throw new Error('SUPABASE_SERVICE_ROLE_KEY eksik');
const sbH = { apikey: sbKey, Authorization: `Bearer ${sbKey}`, 'Content-Type': 'application/json', Prefer: 'return=representation' };

const rows = await this.helpers.httpRequest({ method: 'GET', url: `${sbBase}/rest/v1/social_posts?approval_token=eq.${encodeURIComponent(token)}&limit=1`, headers: sbH, json: true });
if (!rows?.length) throw new Error('Geçersiz onay token');
const post = rows[0];
if (!['pending_approval', 'draft', 'approved', 'scheduled'].includes(post.status)) {
  return [{ json: { ok: false, error: 'Post zaten işlenmiş', status: post.status, post_id: post.id } }];
}

let patch = { updated_at: new Date().toISOString(), approved_by: approvedBy };
if (action === 'reject') {
  patch.status = 'rejected';
} else if (action === 'schedule' && scheduledAt) {
  patch.status = 'scheduled';
  patch.scheduled_at = scheduledAt;
} else {
  patch.status = 'approved';
  if (scheduledAt) {
    patch.status = 'scheduled';
    patch.scheduled_at = scheduledAt;
  }
}

const updated = await this.helpers.httpRequest({ method: 'PATCH', url: `${sbBase}/rest/v1/social_posts?id=eq.${post.id}`, headers: sbH, body: patch, json: true });

const webhookBase = ($env.WEBHOOK_URL || $env.N8N_WEBHOOK_URL || 'http://127.0.0.1:5678/').replace(/\/$/, '');
let publishTriggered = false;
if (patch.status === 'approved') {
  try {
    await this.helpers.httpRequest({ method: 'POST', url: `${webhookBase}/webhook/nefalix/social/publish`, headers: { 'Content-Type': 'application/json' }, body: { post_id: post.id }, json: true });
    publishTriggered = true;
  } catch (e) {
    publishTriggered = false;
  }
}

return [{ json: { ok: true, action, post_id: post.id, new_status: patch.status, publishTriggered, post: updated[0] || null } }];
